import React, { useState, useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { login } from '../store/slices/authSlice';
import { schoolAPI } from '../services/api';
import toast from 'react-hot-toast';

const LOCAL_KEY = 'school_settings';

export default function Login() {
  const [username,   setUsername]   = useState('admin');
  const [password,   setPassword]   = useState('admin123');
  const [loading,    setLoading]    = useState(false);
  const [error,      setError]      = useState('');
  const [schoolInfo, setSchoolInfo] = useState(() => {
    try { return JSON.parse(localStorage.getItem(LOCAL_KEY)) || {}; }
    catch { return {}; }
  });
  const dispatch = useDispatch();
  const navigate = useNavigate();

  // Only clear auth tokens, never settings
  useEffect(() => {
    localStorage.removeItem('accessToken');
    localStorage.removeItem('refreshToken');
    sessionStorage.clear();
  }, []);

  useEffect(() => {
    schoolAPI.getProfile()
      .then(res => {
        const d = res.data.data;
        if (!d) return;
        const s = {
          schoolName:   d.name                   || 'EduErpee',
          tagline:      d.settings?.tagline       || 'School Management System',
          logo:         d.logo_url               || '',
          primaryColor: d.settings?.primaryColor || '#1E1B4B',
          accentColor:  d.settings?.accentColor  || '#F59E0B',
        };
        setSchoolInfo(s);
        const existing = {};
        try { Object.assign(existing, JSON.parse(localStorage.getItem(LOCAL_KEY))||{}); } catch {}
        localStorage.setItem(LOCAL_KEY, JSON.stringify({ ...existing, ...s }));
      })
      .catch(() => {});
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!username || !password) { setError('Please enter username and password'); return; }
    setLoading(true); setError('');

    const res = await dispatch(login({ username: username.trim(), password }));

    if (login.fulfilled.match(res)) {
      toast.success('Welcome back! 👋');
      navigate('/', { replace: true });
    } else {
      const msg = res.payload || 'Login failed';
      setError(msg);
      toast.error(msg);
    }
    setLoading(false);
  };

  const primary = schoolInfo.primaryColor || '#1E1B4B';
  const accent  = schoolInfo.accentColor  || '#F59E0B';
  const name    = schoolInfo.schoolName   || 'EduErpee';
  const tagline = schoolInfo.tagline      || 'School Management System';
  const logo    = schoolInfo.logo         || '';

  return (
    <div style={{
      minHeight:'100vh',
      background:'linear-gradient(135deg, ' + primary + ' 0%, ' + primary + 'DD 50%, ' + accent + '44 100%)',
      display:'flex', alignItems:'center', justifyContent:'center', padding:16,
    }}>
      <div style={{position:'fixed',top:-80,right:-80,width:300,height:300,borderRadius:'50%',background:'rgba(255,255,255,.04)',pointerEvents:'none'}}/>
      <div style={{position:'fixed',bottom:-100,left:-100,width:400,height:400,borderRadius:'50%',background:'rgba(255,255,255,.03)',pointerEvents:'none'}}/>

      <div style={{
        background:'#fff', borderRadius:24, padding:'40px 40px 32px',
        width:440, maxWidth:'100%',
        boxShadow:'0 32px 80px rgba(0,0,0,.25)',
        position:'relative', zIndex:1,
      }}>
        {/* School logo + name */}
        <div style={{textAlign:'center', marginBottom:32}}>
          <div style={{
            width:72, height:72, borderRadius:20,
            background: logo ? '#fff' : 'linear-gradient(135deg,' + primary + ',' + accent + ')',
            border: logo ? '3px solid #E5E7EB' : 'none',
            display:'flex', alignItems:'center', justifyContent:'center',
            margin:'0 auto 16px',
            boxShadow:'0 8px 24px rgba(0,0,0,.18)',
            overflow:'hidden', flexShrink:0,
          }}>
            {logo
              ? <img src={logo} alt="School Logo" style={{width:'100%',height:'100%',objectFit:'cover'}}/>
              : <span style={{fontSize:34}}>🏫</span>}
          </div>
          <h1 style={{fontSize:22,fontWeight:800,color:primary,margin:0,letterSpacing:'-.02em'}}>{name}</h1>
          <p style={{fontSize:13,color:'#9CA3AF',marginTop:5}}>{tagline}</p>
          <div style={{width:40,height:3,background:'linear-gradient(90deg,'+primary+','+accent+')',borderRadius:99,margin:'12px auto 0'}}/>
        </div>

        {/* Error */}
        {error && (
          <div style={{padding:'12px 16px',background:'#FEF2F2',border:'1px solid #FECACA',borderRadius:10,fontSize:13,color:'#DC2626',marginBottom:20,display:'flex',alignItems:'center',gap:8}}>
            <span>⚠️</span> {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <div style={{marginBottom:16}}>
            <label style={{display:'block',fontSize:11,fontWeight:700,color:'#374151',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:7}}>Username</label>
            <input
              type="text" value={username} onChange={e=>setUsername(e.target.value)}
              placeholder="Enter username" autoFocus
              style={{width:'100%',padding:'12px 16px',border:'2px solid #E5E7EB',borderRadius:10,fontSize:14,outline:'none',fontFamily:'inherit',boxSizing:'border-box',transition:'border-color .15s'}}
              onFocus={e=>e.target.style.borderColor=primary}
              onBlur={e=>e.target.style.borderColor='#E5E7EB'}
            />
          </div>

          <div style={{marginBottom:24}}>
            <label style={{display:'block',fontSize:11,fontWeight:700,color:'#374151',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:7}}>Password</label>
            <input
              type="password" value={password} onChange={e=>setPassword(e.target.value)}
              placeholder="Enter password"
              style={{width:'100%',padding:'12px 16px',border:'2px solid #E5E7EB',borderRadius:10,fontSize:14,outline:'none',fontFamily:'inherit',boxSizing:'border-box',transition:'border-color .15s'}}
              onFocus={e=>e.target.style.borderColor=primary}
              onBlur={e=>e.target.style.borderColor='#E5E7EB'}
            />
          </div>

          <button type="submit" disabled={loading}
            style={{width:'100%',padding:'14px',background:loading?'#9CA3AF':primary,color:'#fff',border:'none',borderRadius:12,fontSize:15,fontWeight:700,cursor:loading?'not-allowed':'pointer',transition:'background .15s',letterSpacing:'.01em'}}>
            {loading ? '⏳ Signing in…' : 'Sign In →'}
          </button>
        </form>

        {/* Demo accounts */}
        <div style={{marginTop:24,padding:14,background:'#F9FAFB',borderRadius:12,border:'1px dashed #D1D5DB'}}>
          <p style={{fontSize:10,fontWeight:700,color:'#9CA3AF',textTransform:'uppercase',letterSpacing:'.08em',marginBottom:8}}>
            Quick Login (password: admin123)
          </p>
          <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
            {[
              ['admin',      'Admin',      '#EDE9F8','#4C1D95'],
              ['principal',  'Principal',  '#DBEAFE','#1E40AF'],
              ['teacher1',   'Teacher',    '#D1FAE5','#065F46'],
              ['accountant', 'Accountant', '#FEF3C7','#92400E'],
              ['parent1',    'Parent',     '#FCE7F3','#9D174D'],
            ].map(([u,label,bg,color]) => (
              <button key={u} type="button" onClick={() => { setUsername(u); setPassword('admin123'); }}
                style={{padding:'5px 12px',background:bg,border:'none',borderRadius:20,fontSize:11,fontWeight:600,color,cursor:'pointer'}}>
                {label}
              </button>
            ))}
          </div>
        </div>

        <p style={{textAlign:'center',marginTop:16,fontSize:11,color:'#D1D5DB'}}>
          EduErpee · School ERP · v1.0
        </p>
      </div>
    </div>
  );
}
